  1	import { type FC, Fragment, useState } from 'react';
  2	import { useWatch } from 'react-hook-form';
  3	import { storageMapFieldLabels } from 'src/storageMaps/constants';
  4	
  5	import {
  6	  DescriptionList,
  7	  DescriptionListDescription,
  8	  DescriptionListGroup,
  9	  DescriptionListTerm,
 10	  Stack,
 11	  StackItem,
 12	} from '@patternfly/react-core';
 13	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 14	import { EMPTY_MSG } from '@utils/constants';
 15	
 16	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 17	import { CreatePlanStorageMapFieldId } from '../storage-map/constants';
 18	
 19	const StorageMapReviewTable: FC = () => {
 20	  const { control } = useCreatePlanFormContext();
 21	  const [expandedRows, setExpandedRows] = useState<Set<string>>(new Set());
 22	
 23	  const storageMap = useWatch({
 24	    control,
 25	    name: CreatePlanStorageMapFieldId.StorageMap,
 26	  });
 27	
 28	  if (!storageMap) {
 29	    return null;
 30	  }
 31	
 32	  const hasOffloadStorage = storageMap.some(
 33	    (mapping) => mapping[CreatePlanStorageMapFieldId.OffloadPlugin],
 34	  );
 35	
 36	  const handleToggleExpansion = (rowKey: string) => {
 37	    const newExpandedRows = new Set(expandedRows);
 38	    if (expandedRows.has(rowKey)) {
 39	      newExpandedRows.delete(rowKey);
 40	    } else {
 41	      newExpandedRows.add(rowKey);
 42	    }
 43	    setExpandedRows(newExpandedRows);
 44	  };
 45	
 46	  return (
 47	    <Table aria-label="Storage map review table" variant={TableVariant.compact}>
 48	      <Thead>
 49	        <Tr>
 50	          {hasOffloadStorage && <Th />}
 51	          <Th width={50}>{storageMapFieldLabels[CreatePlanStorageMapFieldId.SourceStorage]}</Th>
 52	          <Th width={50}>{storageMapFieldLabels[CreatePlanStorageMapFieldId.TargetStorage]}</Th>
 53	        </Tr>
 54	      </Thead>
 55	
 56	      <Tbody>
 57	        {storageMap.map((mapping, index) => {
 58	          // Only render rows that have both source and target storage names
 59	          if (
 60	            mapping[CreatePlanStorageMapFieldId.SourceStorage].name &&
 61	            mapping[CreatePlanStorageMapFieldId.TargetStorage].name
 62	          ) {
 63	            const rowKey = `${mapping[CreatePlanStorageMapFieldId.SourceStorage].name}-${index}`;
 64	            const isExpanded = expandedRows.has(rowKey);
 65	            const hasOffloadData =
 66	              mapping[CreatePlanStorageMapFieldId.OffloadPlugin] ??
 67	              mapping[CreatePlanStorageMapFieldId.StorageSecret] ??
 68	              mapping[CreatePlanStorageMapFieldId.StorageProduct];
 69	
 70	            return (
 71	              <Fragment key={rowKey}>
 72	                <Tr>
 73	                  {hasOffloadStorage && (
 74	                    <Td
 75	                      {...(hasOffloadData && {
 76	                        expand: {
 77	                          isExpanded,
 78	                          onToggle: () => {
 79	                            handleToggleExpansion(rowKey);
 80	                          },
 81	                          rowIndex: index,
 82	                        },
 83	                      })}
 84	                    />
 85	                  )}
 86	                  <Td dataLabel={CreatePlanStorageMapFieldId.SourceStorage}>
 87	                    {mapping[CreatePlanStorageMapFieldId.SourceStorage].name}
 88	                  </Td>
 89	                  <Td dataLabel={CreatePlanStorageMapFieldId.TargetStorage}>
 90	                    {mapping[CreatePlanStorageMapFieldId.TargetStorage].name}
 91	                  </Td>
 92	                </Tr>
 93	                {hasOffloadStorage && isExpanded && hasOffloadData && (
 94	                  <Tr isExpanded>
 95	                    <Td />
 96	                    <Td colSpan={3}>
 97	                      <Stack hasGutter className="pf-v6-u-pt-md pf-v6-u-pb-md">
 98	                        <StackItem>
 99	                          <DescriptionList isHorizontal isCompact>
100	                            <DescriptionListGroup>
101	                              <DescriptionListTerm>
102	                                {storageMapFieldLabels[CreatePlanStorageMapFieldId.OffloadPlugin]}
103	                              </DescriptionListTerm>
104	                              <DescriptionListDescription>
105	                                {mapping[CreatePlanStorageMapFieldId.OffloadPlugin] ?? EMPTY_MSG}
106	                              </DescriptionListDescription>
107	                            </DescriptionListGroup>
108	                            <DescriptionListGroup>
109	                              <DescriptionListTerm>
110	                                {storageMapFieldLabels[CreatePlanStorageMapFieldId.StorageSecret]}
111	                              </DescriptionListTerm>
112	                              <DescriptionListDescription>
113	                                {mapping[CreatePlanStorageMapFieldId.StorageSecret] ?? EMPTY_MSG}
114	                              </DescriptionListDescription>
115	                            </DescriptionListGroup>
116	                            <DescriptionListGroup>
117	                              <DescriptionListTerm>
118	                                {storageMapFieldLabels[CreatePlanStorageMapFieldId.StorageProduct]}
119	                              </DescriptionListTerm>
120	                              <DescriptionListDescription>
121	                                {mapping[CreatePlanStorageMapFieldId.StorageProduct] ?? EMPTY_MSG}
122	                              </DescriptionListDescription>
123	                            </DescriptionListGroup>
124	                          </DescriptionList>
125	                        </StackItem>
126	                      </Stack>
127	                    </Td>
128	                  </Tr>
129	                )}
130	              </Fragment>
131	            );
132	          }
133	
134	          return null;
135	        })}
136	      </Tbody>
137	    </Table>
138	  );
139	};
140	
141	export default StorageMapReviewTable;

